// DP and reconstruction
const NEG = -Infinity;
let dp = Array.from({ length: n + 1 }, () => Array(k + 1).fill(NEG));
let prev = Array.from({ length: n + 1 }, () => Array(k + 1).fill(null));
dp[0][0] = 0;
for (let i = 1; i <= n; i++) {
  for (let t = 0; t <= k; t++) {
    dp[i][t] = dp[i - 1][t];
    if (t > 0) {
      for (let l = 1; l <= i; l++) {
        if (isPal[l - 1][i - 1] && dp[l - 1][t - 1] !== NEG) {
          const cand = dp[l - 1][t - 1] + (i - l + 1);
          if (cand > dp[i][t]) {
            dp[i][t] = cand;
            prev[i][t] = [l - 1, t - 1, i - 1];
          }
        }
      }
    }
  }
}
```

## Why This Is Asked

