// Implementation outline
function maxScorePartition(s, k) {
  const n = s.length;
  const dist = Array.from({length:n}, ()=>Array(n).fill(0));
  for (let l=0;l<n;l++) {
    const seen = new Set();
    for (let r=l;r<n;r++) { seen.add(s[r]); dist[l][r] = seen.size; }
  }
  const dp = Array.from({length:n+1}, ()=>Array(k+1).fill(-Infinity));
  const par = Array.from({length:n+1}, ()=>Array(k+1).fill(-1));
  for (let i=1;i<=n;i++) dp[i][1] = dist[0][i-1];
  for (let t=2;t<=k;t++){
    for (let i=t;i<=n;i++){
      for (let j=t-1;j<i;j++){
        const v = dp[j][t-1] + dist[j][i-1];
        if (v > dp[i][t]) { dp[i][t] = v; par[i][t] = j; }
      }
    }
  }
  // reconstruction omitted
  return {dp, par};
}
```

## Why This Is Asked
This problem tests advanced dynamic programming techniques involving multiple non-overlapping segments with per-element costs—a pattern frequently appearing in interviews for algorithm-intensive roles.

## Key Concepts
- Partition DP with fixed number of blocks requiring optimal segmentation
- Prefix sum transformations to simplify recurrence relations
- Time-space optimization strategies and solution reconstruction

## Code Example
```javascript
function maxValue(A, k, c) {
  const n = A.length;
  const P = new Array(n+1).fill(0);
  for (let i = 0; i < n; i++) P[i+1] = P[i] + A[i];

  const B = new Array(n+1).fill(0);
  for (let x = 0; x <= n; x++) B[x] = P[x] - c * x;

  const dp = Array.from({length: n+1}, () => new Array(k+1).fill(-Infinity));
  const parent = Array.from({length: n+1}, () => new Array(k+1).fill(-1));

  dp[0][0] = 0;
  for (let i = 0; i <= n; i++) dp[i][0] = 0;

  for (let t = 1; t <= k; t++) {
    for (let i = 1; i <= n; i++) {
      dp[i][t] = dp[i][t-1];
      for (let j = 0; j < i; j++) {
        const candidate = dp[j][t-1] + B[i] - B[j];
        if (candidate > dp[i][t]) {
          dp[i][t] = candidate;
          parent[i][t] = j;
        }
      }
    }
  }

  // Reconstruct solution
  const blocks = [];
  let curr = n, currT = k;
  while (currT > 0 && parent[curr][currT] !== -1) {
    const start = parent[curr][currT];
    blocks.unshift([start, curr-1]);
    curr = start;
    currT--;
  }

  return { maxValue: dp[n][k], blocks };
}
```

## Implementation Details
- The transformation B[x] = P[x] - c*x captures the net value after maintenance costs
- The nested loop structure ensures we consider all possible segment boundaries
- Parent array enables O(k) reconstruction of optimal segment endpoints

