  const take = Array.from({ length: n + 1 }, () => Array(K + 1).fill(false));
  for (let i = 1; i <= n; i++) {
    for (let j = 0; j <= K; j++) {
      dp[i][j] = dp[i - 1][j];
      if (j > 0) {
        if (i >= 2) {
          const cand = dp[i - 2][j - 1] + A[i - 1];
          if (cand > dp[i][j]) {
            dp[i][j] = cand;
            take[i][j] = true;
          }
        } else if (i === 1 && j === 1) {
          if (A[0] > dp[i][j]) { dp[i][j] = A[0]; take[i][j] = true; }
        }
      }
    }
  }
  // reconstruct
  let i = n, j = K, indices = [];
  while (i >= 1 && j >= 0) {
    if (take[i][j]) { indices.push(i - 1); i -= 2; j -= 1; }
    else { i -= 1; }
