  for (let i = 1; i <= n; i++) dp[i][1] = pref[i-1];
  for (let t = 2; t <= k; t++) {
    let best = -Infinity, bestP = -1;
    for (let i = t; i <= n; i++) {
      const p = i - 1;
      const val = dp[p][t-1] - pref[p];
      if (val > best) { best = val; bestP = p; }
      dp[i][t] = pref[i-1] + best;
      take[i][t] = bestP;
