  const dp = Array.from({ length: n + 1 }, () => Array(k + 1).fill(-Infinity));
  const bt = Array.from({ length: n + 1 }, () => Array(k + 1).fill(-1));
  for (let i = 1; i <= n; i++) dp[i][1] = D[0][i - 1];
  for (let t = 2; t <= k; t++) {
    for (let i = t; i <= n; i++) {
      for (let p = t - 1; p <= i - 1; p++) {
        const cand = dp[p][t - 1] + D[p][i - 1];
        if (cand > dp[i][t]) { dp[i][t] = cand; bt[i][t] = p; }
