  hold[0] = -prices[0];
  for (let i=1;i<n;i++){
    let nno=no.slice(), nhold=hold.slice(), ncool=cool.slice();
    for (let t=0;t<=k;t++){
      nno[t] = Math.max(nno[t], cool[t]);
      nhold[t] = Math.max(nhold[t], no[t] - prices[i]);
      if (t>0) ncool[t] = Math.max(ncool[t], hold[t-1] + prices[i]);
    }
    no=nno; hold=nhold; cool=ncool;
  }
  let best=0; for (let t=0;t<=k;t++) best=Math.max(best,no[t],cool[t]);
  return best;
}
