```javascript
function maxScorePartition(A, k) {
  const n = A.length;
  const P = [0];
  for (let x of A) P.push(P[P.length-1] + x);
  const dp = Array.from({length: n+1}, () => new Array(k+1).fill(-Infinity));
  const parent = Array.from({length: n+1}, () => new Array(k+1).fill(-1));

  for (let i = 1; i <= n; i++) {
    dp[i][1] = P[i];
  }

  for (let t = 2; t <= k; t++) {
    for (let i = t; i <= n; i++) {
      for (let p = t-1; p < i; p++) {
        const score = dp[p][t-1] + (P[i] - P[p]) * t;
        if (score > dp[i][t]) {
          dp[i][t] = score;
          parent[i][t] = p;
        }
      }
    }
  }

  // Reconstruct partitions
  const partitions = [];
  let end = n;
  for (let t = k; t >= 1; t--) {
    const start = parent[end][t];
    partitions.unshift([start+1, end]);
    end = start;
  }

  return { maxScore: dp[n][k], partitions };
}
```

