function maxSumSplit(s, k){
  const n = s.length;
  const val = (a,b)=> BigInt(s.slice(a,b));
  const dp = Array.from({length: n+1}, () => Array(k+1).fill(-1n));
  const prev = Array.from({length: n+1}, () => Array(k+1).fill(-1));

  for(let i=1;i<=n;i++){
    dp[i][1] = val(0,i);
  }

  for(let t=2;t<=k;t++){
    for(let i=t;i<=n;i++){
      for(let j=t-1;j<i;j++){
        const candidate = dp[j][t-1] + val(j,i);
        if(candidate > dp[i][t]){
          dp[i][t] = candidate;
          prev[i][t] = j;
        }
      }
    }
  }

  // Reconstruct splits
  const splits = [];
  let curr = n, parts = k;
  while(parts > 1){
    const j = prev[curr][parts];
    splits.push(j);
    curr = j;
    parts--;
  }
  splits.reverse();

  return {maxSum: dp[n][k], splits};
}
```

