function minCostWithDiscount(grid){
  const n = grid.length, m = grid[0].length;
  const INF = 1e15;
  let dp0 = new Array(m).fill(INF);
  let dp1 = new Array(m).fill(INF);
  dp0[0] = grid[0][0];
  dp1[0] = Math.floor(grid[0][0] / 2);
  for (let j = 1; j < m; j++) {
    dp0[j] = grid[0][j] + dp0[j-1];
    dp1[j] = Math.min(grid[0][j] + dp1[j-1], Math.floor(grid[0][j]/2) + dp0[j-1]);
  }
  for (let i = 1; i < n; i++) {
    dp0[0] += grid[i][0];
    dp1[0] = Math.min(grid[i][0] + dp1[0], Math.floor(grid[i][0]/2) + dp0[0-1]);
    for (let j = 1; j < m; j++) {
      const v = grid[i][j];
      dp1[j] = Math.min(v + Math.min(dp1[j], dp1[j-1]), Math.floor(v/2) + Math.min(dp0[j], dp0[j-1]));
      dp0[j] = v + Math.min(dp0[j], dp0[j-1]);
    }
  }
  return dp1[m-1];
}
```

