function minMaxRisk(r) {
  const n = r.length, m = r[0].length;
  const INF = Number.POSITIVE_INFINITY;
  const dp = Array.from({length: n}, () => Array(m).fill(INF));
  const from = Array.from({length: n}, () => Array(m).fill(-1));
  dp[0][0] = r[0][0];
  for (let j = 1; j < m; j++) { dp[0][j] = Math.max(dp[0][j-1], r[0][j]); from[0][j] = 0; }
  for (let i = 1; i < n; i++) { dp[i][0] = Math.max(dp[i-1][0], r[i][0]); from[i][0] = 1; }
  for (let i = 1; i < n; i++) {
    for (let j = 1; j < m; j++) {
      const up = Math.max(dp[i-1][j], r[i][j]);
      const left = Math.max(dp[i][j-1], r[i][j]);
      if (up <= left) { dp[i][j] = up; from[i][j] = 0; } else { dp[i][j] = left; from[i][j] = 1; }
    }
  }
  return {minMaxRisk: dp[n-1][m-1], parent: from};
}
