function minWrap(words, W) {
  const n = words.length;
  const pref = new Array(n + 1).fill(0);
  for (let i = 0; i < n; i++) pref[i + 1] = pref[i] + words[i];
  const dp = new Array(n + 1).fill(Infinity);
  const nxt = new Array(n).fill(-1);
  dp[n] = 0;
  for (let i = n - 1; i >= 0; i--) {
    for (let j = i; j < n; j++) {
      const width = (pref[j + 1] - pref[i]) + (j - i);
      if (width <= W) {
        const cost = (W - width) * (W - width) + dp[j + 1];
        if (cost < dp[i]) { dp[i] = cost; nxt[i] = j + 1; }
      } else break;
    }
  }
  // reconstruction omitted for brevity
  return { minPenalty: dp[0], next: nxt };
}
