function maxRevenue(A, k) {
  const n = A.length;
  const S = Array(n+1).fill(0);
  for (let i=1;i<=n;i++) S[i] = S[i-1] + A[i-1];
  const dp = Array.from({length:n+1}, ()=>Array(k+1).fill(-Infinity));
  const par = Array.from({length:n+1}, ()=>Array(k+1).fill(-1));
  for (let i=1;i<=n;i++) dp[i][1] = S[i]*i;
  for (let t=2;t<=k;t++) {
    for (let i=t;i<=n;i++) {
      for (let p=t-1;p<=i-1;p++) {
        const val = dp[p][t-1] + (S[i]-S[p])*(i-p);
        if (val > dp[i][t]) { dp[i][t] = val; par[i][t] = p; }
      }
    }
  }
  // reconstruction
  let i=n, t=k; const ends=[];
  while (t>0) { const p = par[i][t]; ends.push([p+1, i]); i = p; t--; }
  ends.reverse();
  return {value: dp[n][k], windows: ends};
}
