function minCostPartition(A, k) {
  const n = A.length;
  const maxv = Array.from({length: n}, () => Array(n).fill(0));
  const minv = Array.from({length: n}, () => Array(n).fill(0));
  for (let i = 0; i < n; i++) {
    maxv[i][i] = A[i];
    minv[i][i] = A[i];
    for (let j = i + 1; j < n; j++) {
      maxv[i][j] = Math.max(maxv[i][j-1], A[j]);
      minv[i][j] = Math.min(minv[i][j-1], A[j]);
    }
  }
  const INF = 1e18;
  const dp = Array.from({length: n+1}, () => Array(k+1).fill(INF));
  const par = Array.from({length: n+1}, () => Array(k+1).fill(-1));
  dp[0][0] = 0;
  for (let i = 1; i <= n; i++) dp[i][1] = (maxv[0][i-1]-minv[0][i-1]) * i, par[i][1] = 0;
  for (let t = 2; t <= k; t++) {
    for (let i = t; i <= n; i++) {
      for (let p = t-1; p <= i-1; p++) {
        const cost = (maxv[p][i-1]-minv[p][i-1]) * (i-p);
        if (dp[p][t-1] + cost < dp[i][t]) {
          dp[i][t] = dp[p][t-1] + cost;
          par[i][t] = p;
        }
      }
    }
  }
  let idx = n, rem = k, cuts = [];
  while (rem > 0) {
    const p = par[idx][rem];
    cuts.push([p, idx-1]);
    idx = p; rem--;
  }
  cuts.reverse();
  return {cost: dp[n][k], blocks: cuts};
}
```

