function minCostSchedule(A, m, D) {
  const n = A.length;
  const pref = new Array(n + 1).fill(0);
  for (let i = 1; i <= n; i++) pref[i] = pref[i - 1] + A[i - 1];
  const INF = Number.POSITIVE_INFINITY;
  const dp = Array.from({ length: n + 1 }, () => new Array(m + 1).fill(INF));
  const par = Array.from({ length: n + 1 }, () => new Array(m + 1).fill(-1));
  dp[0][0] = 0;
  for (let d = 1; d <= m; d++) {
    for (let i = 1; i <= n; i++) {
      for (let j = 0; j < i; j++) {
        const sum = pref[i] - pref[j];
        if (sum <= D && dp[j][d - 1] !== INF) {
          const cost = dp[j][d - 1] + sum * sum;
          if (cost < dp[i][d]) {
            dp[i][d] = cost;
            par[i][d] = j;
          }
        }
      }
    }
  }
  if (dp[n][m] === INF) return { cost: -1, blocks: [] };
  const blocks = [];
  let i = n, d = m;
  while (d > 0) {
    const j = par[i][d];
    blocks.push([j + 1, i]);
    i = j;
    d--;
  }
  blocks.reverse();
  return { cost: dp[n][m], blocks };
}
