  const n = s.length;
  // val[i][j] = value of s[i..j-1]
  const val = Array.from({ length: n+1 }, () => Array(n+1).fill(0));
  for (let i = 0; i < n; i++) {
    if (s[i] === '0') { val[i][i+1] = 0; continue; }
    let cur = 0;
    for (let j = i; j < n; j++) {
