      val[i][j+1] = cur;
    }
  }
  const dp = Array.from({ length: n+1 }, () => Array(k+1).fill(-Infinity));
  const par = Array.from({ length: n+1 }, () => Array(k+1).fill(-1));
  for (let i = 1; i <= n; i++) dp[i][1] = val[0][i];
  for (let t = 2; t <= k; t++) {
    for (let i = t; i <= n; i++) {
      for (let j = t-1; j < i; j++) {
        if (s[j] === '0' && i - j > 1) continue;
        const cand = dp[j][t-1] + val[j][i];
        if (cand > dp[i][t]) { dp[i][t] = cand; par[i][t] = j; }
      }
    }
  }
  // reconstruct cuts
  const cuts = [];
  let i = n, t = k;
  while (t > 0) {
    const j = par[i][t];
    cuts.push(i);
    i = j;
    t--;
  }
  cuts.push(0);
  cuts.reverse();
